// Generated by forge proof from consolidate-scoped-typecheck.md
import { describe, test, expect, beforeAll, afterAll, beforeEach, afterEach } from 'bun:test';
import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import { setupHermeticGit, teardownHermeticGit } from './test-utils.js';
import { parseScope } from './deps.js';
import { detectVerification } from './verify.js';

// ── Hermetic Git ─────────────────────────────────────────────

beforeAll(() => { setupHermeticGit(); });
afterAll(() => { teardownHermeticGit(); });

// ── Helpers ──────────────────────────────────────────────────

let tmpDir: string;

beforeEach(async () => {
  tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-scoped-tc-test-'));
});

afterEach(async () => {
  await fs.rm(tmpDir, { recursive: true, force: true });
});

/** Create a minimal monorepo directory structure. */
async function createMonorepoStructure(root: string, opts?: { rootTsconfig?: boolean }) {
  await fs.writeFile(path.join(root, 'package.json'), JSON.stringify({
    name: 'monorepo-root',
    private: true,
    workspaces: ['packages/*'],
  }));
  await fs.writeFile(path.join(root, 'bun.lockb'), '');

  if (opts?.rootTsconfig !== false) {
    await fs.writeFile(path.join(root, 'tsconfig.json'), JSON.stringify({
      compilerOptions: { strict: true },
    }));
  }
}

/** Create a scoped package with optional tsconfig. */
async function createScopedPackage(root: string, scope: string, opts?: { hasTsconfig?: boolean; hasBuild?: boolean }) {
  const pkgDir = path.join(root, scope);
  await fs.mkdir(pkgDir, { recursive: true });

  const scripts: Record<string, string> = {};
  if (opts?.hasBuild !== false) scripts.build = 'tsc -b';

  await fs.writeFile(path.join(pkgDir, 'package.json'), JSON.stringify({
    name: `@test/${path.basename(scope)}`,
    scripts,
  }));

  if (opts?.hasTsconfig !== false) {
    await fs.writeFile(path.join(pkgDir, 'tsconfig.json'), JSON.stringify({
      compilerOptions: { strict: true },
    }));
  }
}

// ── Scope from spec frontmatter ─────────────────────────────

describe('scoped typecheck: scope from spec frontmatter', () => {
  test('parseScope extracts scope used by runIncrementalTypeCheck', () => {
    const specContent = `---
scope: packages/api
depends: [base.md]
---

# API spec`;
    const scope = parseScope(specContent);
    expect(scope).toBe('packages/api');
  });

  test('no scope defaults to root-level verification', () => {
    const specContent = `---
depends: [base.md]
---

# Root spec`;
    const scope = parseScope(specContent);
    expect(scope).toBeUndefined();
  });
});

// ── Scoped tsconfig detection ───────────────────────────────

describe('scoped typecheck: tsconfig detection', () => {
  test('detects tsconfig.json in scoped package directory', async () => {
    await createMonorepoStructure(tmpDir);
    await createScopedPackage(tmpDir, 'packages/api');

    const scopedDir = path.join(tmpDir, 'packages/api');
    const hasTsconfig = await fs.access(path.join(scopedDir, 'tsconfig.json')).then(() => true).catch(() => false);
    expect(hasTsconfig).toBe(true);
  });

  test('falls through to default when scoped dir has no tsconfig', async () => {
    await createMonorepoStructure(tmpDir);
    await createScopedPackage(tmpDir, 'packages/raw', { hasTsconfig: false });

    const scopedDir = path.join(tmpDir, 'packages/raw');
    const hasTsconfig = await fs.access(path.join(scopedDir, 'tsconfig.json')).then(() => true).catch(() => false);
    expect(hasTsconfig).toBe(false);
    // When hasTsconfig is false, runIncrementalTypeCheck falls through to detectVerification at root
  });

  test('detects root tsconfig for second-pass check', async () => {
    await createMonorepoStructure(tmpDir, { rootTsconfig: true });

    const hasRootTsconfig = await fs.access(path.join(tmpDir, 'tsconfig.json')).then(() => true).catch(() => false);
    expect(hasRootTsconfig).toBe(true);
  });

  test('no root tsconfig means scoped check is sufficient', async () => {
    await createMonorepoStructure(tmpDir, { rootTsconfig: false });
    await createScopedPackage(tmpDir, 'packages/standalone');

    const hasRootTsconfig = await fs.access(path.join(tmpDir, 'tsconfig.json')).then(() => true).catch(() => false);
    expect(hasRootTsconfig).toBe(false);
    // When no root tsconfig, scoped pass is the only pass needed
  });
});

// ── Two-pass type-check logic ───────────────────────────────

describe('scoped typecheck: two-pass logic', () => {
  test('scoped failure returns immediately without root check', () => {
    // Simulate runIncrementalTypeCheck logic
    const scopeResult = { passed: false, errors: 'packages/api/src/index.ts(5,3): error TS2345' };
    const rootChecked = scopeResult.passed; // Would only check root if scoped passes

    expect(rootChecked).toBe(false);
    expect(scopeResult.errors).toContain('packages/api');
  });

  test('scoped success triggers root check if root tsconfig exists', () => {
    const scopeResult = { passed: true, errors: '' };
    const hasRootTsconfig = true;

    let shouldCheckRoot = false;
    if (scopeResult.passed && hasRootTsconfig) {
      shouldCheckRoot = true;
    }

    expect(shouldCheckRoot).toBe(true);
  });

  test('scoped success with no root tsconfig returns passed', () => {
    const scopeResult = { passed: true, errors: '' };
    const hasRootTsconfig = false;

    let finalResult = scopeResult;
    if (scopeResult.passed && hasRootTsconfig) {
      // Would run root check
    } else if (scopeResult.passed) {
      finalResult = { passed: true, errors: '' };
    }

    expect(finalResult.passed).toBe(true);
  });
});

// ── Fix agent receives scope context ────────────────────────

describe('scoped typecheck: fix agent scope context', () => {
  test('scope is included in fix agent prompt', () => {
    const scope = 'packages/api';
    const errors = 'packages/api/src/index.ts(5,3): error TS2345: Argument...';
    const branch = 'forge/api-auth';

    // Simulate the scopeContext string from fixTypeErrors()
    const scopeContext = scope
      ? `\n\n## Scope\n\nThe errors originate from the \`${scope}\` package. Focus your fixes on files within that package directory first.`
      : '';

    expect(scopeContext).toContain('packages/api');
    expect(scopeContext).toContain('Focus your fixes');
  });

  test('no scope omits scope section from prompt', () => {
    const scope: string | undefined = undefined;
    const scopeContext = scope
      ? `\n\n## Scope\n\nThe errors originate from the \`${scope}\` package.`
      : '';

    expect(scopeContext).toBe('');
  });
});

// ── Default behavior preserved when no scope ────────────────

describe('scoped typecheck: default behavior without scope', () => {
  test('detectVerification at root works for single-package project', async () => {
    await fs.writeFile(path.join(tmpDir, 'package.json'), JSON.stringify({
      scripts: { build: 'tsc' },
      devDependencies: { typescript: '^5.0.0' },
    }));
    await fs.writeFile(path.join(tmpDir, 'tsconfig.json'), '{}');
    await fs.writeFile(path.join(tmpDir, 'bun.lockb'), '');

    const commands = await detectVerification(tmpDir);
    const hasTsc = commands.some(c => c.includes('tsc --noEmit'));
    expect(hasTsc).toBe(true);
  });

  test('no scope and no tsconfig project returns empty commands', async () => {
    const emptyDir = path.join(tmpDir, 'empty');
    await fs.mkdir(emptyDir, { recursive: true });

    const commands = await detectVerification(emptyDir);
    expect(commands.length).toBe(0);
  });
});

// ── Multiple worktrees targeting different packages ─────────

describe('scoped typecheck: per-merge scope isolation', () => {
  test('each merge type-check scopes to its own package', () => {
    const merges = [
      { spec: 'api-auth.md', scope: 'packages/api' },
      { spec: 'web-ui.md', scope: 'packages/web' },
      { spec: 'shared-types.md', scope: 'packages/shared' },
    ];

    // Each merge's scope is independent
    for (const merge of merges) {
      expect(merge.scope).toBeTruthy();
    }

    // No two merges share the same scope
    const scopes = merges.map(m => m.scope);
    const uniqueScopes = new Set(scopes);
    expect(uniqueScopes.size).toBe(scopes.length);
  });

  test('scope derived from spec frontmatter during merge', () => {
    const specContents: Record<string, string> = {
      'api.md': `---\nscope: packages/api\n---\n# API`,
      'web.md': `---\nscope: packages/web\n---\n# Web`,
      'root.md': `---\n---\n# Root feature`,
    };

    const scopes = Object.entries(specContents).map(([name, content]) => ({
      name,
      scope: parseScope(content),
    }));

    expect(scopes.find(s => s.name === 'api.md')!.scope).toBe('packages/api');
    expect(scopes.find(s => s.name === 'web.md')!.scope).toBe('packages/web');
    expect(scopes.find(s => s.name === 'root.md')!.scope).toBeUndefined();
  });
});
